// Manual iterator:
function counter(max) {
  let i = 0;
  return {
    next() {
      if (i < max) return { value: i++, done: false };
      return { value: undefined, done: true };
    }
  };
}

const iter = counter(3);
console.log(iter.next()); // { value: 0, done: false }
console.log(iter.next()); // { value: 1, done: false }
console.log(iter.next()); // { value: 2, done: false }
console.log(iter.next()); // { value: undefined, done: true }

function* counter(max) {
  for (let i = 0; i < max; i++) {
    yield i;  // pause here, emit i
  }
}

const gen = counter(3);
console.log(gen.next()); // { value: 0, done: false }
console.log(gen.next()); // { value: 1, done: false }
console.log(gen.next()); // { value: 2, done: false }
console.log(gen.next()); // { value: undefined, done: true }

function* range(start, end, step = 1) {
  for (let i = start; i <= end; i += step) {
    yield i;
  }
}

// for...of:
for (const n of range(1, 5)) {
  process.stdout.write(n + " ");
}
console.log();

// Spread:
console.log([...range(0, 10, 2)]);

// Destructuring:
const [a, b, c] = range(100, 300, 100);
console.log(a, b, c);

function* naturals() {
  let n = 1;
  while (true) {   // infinite!
    yield n++;
  }
}

function take(gen, n) {
  const result = [];
  for (const val of gen) {
    result.push(val);
    if (result.length === n) break;
  }
  return result;
}

console.log(take(naturals(), 5));    // [1, 2, 3, 4, 5]
console.log(take(naturals(), 10));   // first 10 naturals

function* numbers() { yield 1; yield 2; yield 3; }
function* letters() { yield 'a'; yield 'b'; yield 'c'; }

function* combined() {
  yield* numbers();
  yield 99;         // regular yield
  yield* letters();
  yield* [10, 20]; // works with arrays too!
}

console.log([...combined()]);

function* calculator() {
  let result = 0;
  while (true) {
    const op = yield result;
    if (!op) break;
    if (op.action === 'add')  result += op.value;
    if (op.action === 'sub')  result -= op.value;
    if (op.action === 'mul')  result *= op.value;
  }
}

const calc = calculator();
console.log(calc.next().value);                          // 0
console.log(calc.next({ action: 'add', value: 10 }).value); // 10
console.log(calc.next({ action: 'mul', value: 3  }).value); // 30
console.log(calc.next({ action: 'sub', value: 5  }).value); // 25

class NumberRange {
  constructor(start, end) {
    this.start = start;
    this.end = end;
  }

  [Symbol.iterator]() {
    let current = this.start;
    const end = this.end;
    return {
      next() {
        if (current <= end) return { value: current++, done: false };
        return { value: undefined, done: true };
      }
    };
  }
}

const r = new NumberRange(1, 5);
for (const n of r) process.stdout.write(n + " ");
console.log();
console.log([...r]);
const [first, , third] = r;
console.log(first, third);

